card.css:
:host {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 0;
}

ha-card,
.shell,
.runtime,
.runtime-content {
  width: 100% !important;
  height: 100% !important;
  min-height: 0 !important;
  box-sizing: border-box !important;
  background: transparent !important;
  box-shadow: none !important;
}

.shell {
  padding: 0 !important;
  gap: 0 !important;
  overflow: visible !important;
}

.runtime,
.runtime-content {
  overflow: visible !important;
}

.neo-light-card {
  --nlc-on: #ffd95a;
  --nlc-alt: #4aa7ff;
  --nlc-off: #6f7f96;
  --nlc-current: var(--nlc-off);
  --nlc-brightness: 0%;
  --nlc-default-surface: linear-gradient(145deg, #0a0f1c, #121a2b 58%, #070b13);
  --nlc-surface-background: var(--nlc-design-surface, var(--ddc-card-inner-bg, var(--ddc-card-local-bg, var(--ddc-card-bg, var(--nlc-default-surface)))));
  --nlc-surface-border: transparent;
  --nlc-x-scale: 1;
  --nlc-y-scale: 1;
  --nlc-ui-scale: 1;
  --nlc-radius: 42px;

  width: 100%;
  height: 100%;
  min-width: 50px;
  min-height: 50px;
  position: relative;
  overflow: visible;
  box-sizing: border-box;
  background: transparent;
}

.neo-light-card[data-active="on"] {
  --nlc-current: var(--nlc-on);
}

.neo-light-card[data-active="on"][data-has-color="true"],
.neo-light-card[data-active="on"][data-has-temperature="true"] {
  --nlc-current: var(--nlc-live-color, var(--nlc-on));
}

.nlc-stage {
  width: 360px;
  height: 500px;
  position: absolute;
  top: 0;
  left: 0;
  border-radius: var(--nlc-radius);
  transform-origin: top left;
  will-change: width, height;
}

.nlc-switch {
  width: 100%;
  height: 100%;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
  border-radius: var(--nlc-radius);
  border: 1px solid var(--nlc-surface-border);
  color: #f7fbff;
  background:
    radial-gradient(circle at 50% 38%, color-mix(in srgb, var(--nlc-current) 12%, transparent), transparent 35%),
    radial-gradient(circle at 50% 52%, rgba(255,255,255,.045), transparent 54%),
    var(--nlc-surface-background);
  box-shadow: inset 0 1px 0 rgba(255,255,255,.065);
  cursor: pointer;
  outline: none;
  user-select: none;
  touch-action: manipulation;
}

.nlc-switch::before,
.nlc-switch::after {
  content: "";
  position: absolute;
  inset: 1px;
  border-radius: inherit;
  pointer-events: none;
}

.nlc-switch::before {
  background:
    linear-gradient(180deg, rgba(255,255,255,.09), transparent 38%),
    radial-gradient(circle at 50% 102%, color-mix(in srgb, var(--nlc-current) 16%, transparent), transparent 34%);
}

.nlc-switch::after {
  inset: 0;
  background:
    linear-gradient(90deg, transparent, rgba(255,255,255,.033), transparent),
    radial-gradient(circle at 48% 42%, color-mix(in srgb, var(--nlc-current) 10%, transparent), transparent 33%);
}

.nlc-switch:focus-visible {
  border-color: color-mix(in srgb, var(--nlc-current) 70%, rgba(255,255,255,.25));
  outline: 3px solid color-mix(in srgb, var(--nlc-current) 32%, transparent);
  outline-offset: -2px;
  box-shadow: inset 0 1px 0 rgba(255,255,255,.065);
}

.neo-light-card[data-surface="transparent"] .nlc-switch {
  background: transparent;
  border-color: transparent;
  box-shadow: none;
}

.neo-light-card[data-surface="transparent"] .nlc-switch::before,
.neo-light-card[data-surface="transparent"] .nlc-switch::after {
  display: none;
}

.neo-light-card[data-surface="transparent"] .nlc-ambient {
  display: none;
}

.nlc-ambient {
  position: absolute;
  left: 50%;
  top: 45%;
  width: 210px;
  height: 210px;
  border-radius: 50%;
  transform: translate(-50%, -50%);
  background: radial-gradient(circle, color-mix(in srgb, var(--nlc-current) 23%, transparent), transparent 66%);
  opacity: .78;
  z-index: 0;
  transition: opacity .3s ease, transform .35s ease;
}

.neo-light-card[data-active="off"] .nlc-ambient {
  opacity: .16;
  transform: translate(-50%, -50%) scale(.82);
}

.nlc-element {
  display: none;
  position: absolute;
  z-index: 2;
}

.nlc-top-icon {
  position: absolute;
  left: 50%;
  top: calc(70px * var(--nlc-y-scale));
  z-index: 4;
  display: none;
  color: var(--nlc-current);
  --mdc-icon-size: calc(42px * var(--nlc-ui-scale));
  transform: translateX(-50%);
  filter: drop-shadow(0 0 15px color-mix(in srgb, var(--nlc-current) 34%, transparent));
  pointer-events: none;
  transition: color .25s ease, opacity .25s ease;
}

.neo-light-card[data-active="off"] .nlc-top-icon {
  opacity: .66;
  filter: none;
}

.neo-light-card[data-style="toggle-switch"] .nlc-top-icon,
.neo-light-card[data-style="circle-button"] .nlc-top-icon,
.neo-light-card[data-style="icon-switch"] .nlc-top-icon,
.neo-light-card[data-style="rocker-switch"] .nlc-top-icon,
.neo-light-card[data-style="ring-dimmer"] .nlc-top-icon,
.neo-light-card[data-style="minimal-dot"] .nlc-top-icon,
.neo-light-card[data-style="slider-switch-horizontal"] .nlc-top-icon {
  display: block;
}

.neo-light-card[data-style="toggle-switch"] .nlc-top-icon { top: calc(82px * var(--nlc-y-scale)); }
.neo-light-card[data-style="circle-button"] .nlc-top-icon { top: calc(34px * var(--nlc-y-scale)); }
.neo-light-card[data-style="icon-switch"] .nlc-top-icon { top: calc(48px * var(--nlc-y-scale)); }
.neo-light-card[data-style="rocker-switch"] .nlc-top-icon { top: calc(22px * var(--nlc-y-scale)); }
.neo-light-card[data-style="ring-dimmer"] .nlc-top-icon { top: calc(24px * var(--nlc-y-scale)); }
.neo-light-card[data-style="minimal-dot"] .nlc-top-icon { top: calc(32px * var(--nlc-y-scale)); }
.neo-light-card[data-style="slider-switch-horizontal"] .nlc-top-icon { top: calc(124px * var(--nlc-y-scale)); }

.neo-light-card[data-style="toggle-switch"] .nlc-meta-icon,
.neo-light-card[data-style="circle-button"] .nlc-meta-icon,
.neo-light-card[data-style="icon-switch"] .nlc-meta-icon,
.neo-light-card[data-style="rocker-switch"] .nlc-meta-icon,
.neo-light-card[data-style="ring-dimmer"] .nlc-meta-icon,
.neo-light-card[data-style="minimal-dot"] .nlc-meta-icon,
.neo-light-card[data-style="slider-switch-horizontal"] .nlc-meta-icon {
  display: none;
}

.nlc-meta {
  position: absolute;
  left: 50%;
  right: auto;
  width: 308px;
  bottom: calc(42px * var(--nlc-y-scale));
  z-index: 4;
  display: grid;
  justify-items: center;
  gap: 10px;
  text-align: center;
  pointer-events: none;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: bottom center;
}

.nlc-meta-icon {
  color: var(--nlc-current);
  --mdc-icon-size: 42px;
  filter: drop-shadow(0 0 15px color-mix(in srgb, var(--nlc-current) 34%, transparent));
  transition: color .25s ease, opacity .25s ease;
}

.neo-light-card[data-active="off"] .nlc-meta-icon {
  opacity: .68;
  filter: none;
}

.neo-light-card[data-show-icon="false"] .nlc-top-icon,
.neo-light-card[data-show-icon="false"] .nlc-meta-icon,
.neo-light-card[data-show-icon="false"] .nlc-card-inner > ha-icon,
.neo-light-card[data-show-icon="false"] .nlc-circle-button > ha-icon,
.neo-light-card[data-show-icon="false"] .nlc-ring-core ha-icon,
.neo-light-card[data-show-icon="false"] .nlc-icon-side ha-icon {
  display: none !important;
}

.nlc-label {
  max-width: 100%;
  color: rgba(232,240,255,.72);
  font-size: 24px;
  font-weight: 700;
  line-height: 1.12;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.nlc-status-row {
  min-height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  color: var(--nlc-current);
  font-size: 22px;
  font-weight: 900;
  letter-spacing: .02em;
  text-transform: uppercase;
}

.nlc-percent {
  color: rgba(232,240,255,.58);
  font-size: 18px;
  font-weight: 800;
  letter-spacing: 0;
  text-transform: none;
}

.neo-light-card[data-show-brightness="false"] .nlc-percent,
.neo-light-card[data-active="off"] .nlc-percent {
  display: none;
}

.neo-light-card[data-show-status="false"] .nlc-status-row,
.neo-light-card[data-show-status="false"] .nlc-card-pill {
  display: none !important;
}

.neo-light-card[data-unavailable="true"] .nlc-switch {
  filter: saturate(.55);
}

.neo-light-card[data-unavailable="true"] .nlc-status {
  color: #ff8a8a;
}

.neo-light-card[data-style="toggle-switch"] .nlc-toggle-track {
  display: block;
}

.nlc-toggle-track {
  left: 50%;
  top: calc(170px * var(--nlc-y-scale));
  width: 264px;
  height: 98px;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  border-radius: 999px;
  background: linear-gradient(145deg, rgba(5,10,18,.78), rgba(45,57,78,.52));
  border: 2px solid rgba(170,190,225,.14);
  box-shadow:
    inset 0 4px 12px rgba(0,0,0,.48),
    inset 0 -1px 0 rgba(255,255,255,.08),
    0 0 0 1px rgba(0,0,0,.18);
}

.nlc-toggle-knob {
  position: absolute;
  top: 10px;
  left: 11px;
  width: 78px;
  height: 78px;
  border-radius: 50%;
  background: linear-gradient(145deg, #f8fbff, #cfe3ff);
  box-shadow:
    0 14px 34px rgba(0,0,0,.38),
    0 0 0 1px rgba(255,255,255,.28) inset;
  transition: transform .42s cubic-bezier(.22, 1, .36, 1), box-shadow .25s ease;
}

.neo-light-card[data-active="on"] .nlc-toggle-track {
  background:
    linear-gradient(90deg, color-mix(in srgb, var(--nlc-alt) 62%, rgba(5,10,18,.8)), color-mix(in srgb, var(--nlc-current) 48%, rgba(5,10,18,.74))),
    linear-gradient(145deg, rgba(5,10,18,.78), rgba(45,57,78,.52));
  box-shadow:
    inset 0 3px 10px rgba(0,0,0,.38),
    0 0 28px color-mix(in srgb, var(--nlc-current) 28%, transparent);
}

.neo-light-card[data-active="on"] .nlc-toggle-knob {
  transform: translateX(164px);
  box-shadow:
    0 14px 34px rgba(0,0,0,.42),
    0 0 30px color-mix(in srgb, var(--nlc-alt) 54%, transparent),
    0 0 0 1px rgba(255,255,255,.42) inset;
}

.neo-light-card[data-style="slider-switch"] .nlc-slider-vertical,
.neo-light-card[data-style="slider-switch-horizontal"] .nlc-slider-horizontal {
  display: block;
}

.nlc-slider-control {
  left: 50%;
  top: calc(88px * var(--nlc-y-scale));
  width: 132px;
  height: var(--nlc-slider-vertical-height, 272px);
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  touch-action: none;
}

.nlc-slider-shell {
  position: absolute;
  left: 35px;
  top: 0;
  width: 62px;
  height: var(--nlc-slider-vertical-shell-height, 238px);
  border-radius: 999px;
  background: rgba(19,30,48,.78);
  border: 1px solid rgba(170,190,225,.13);
  box-shadow:
    inset 0 4px 14px rgba(0,0,0,.44),
    inset 0 0 0 8px rgba(255,255,255,.025);
  overflow: hidden;
}

.nlc-slider-fill {
  position: absolute;
  left: 10px;
  right: 10px;
  bottom: 12px;
  height: var(--nlc-brightness);
  max-height: calc(100% - 24px);
  border-radius: 999px;
  background: linear-gradient(180deg, color-mix(in srgb, var(--nlc-current) 88%, white 8%), var(--nlc-alt));
  transition: height .36s cubic-bezier(.22, 1, .36, 1);
}

.nlc-slider-knob {
  position: absolute;
  left: 50%;
  bottom: clamp(18px, calc(var(--nlc-brightness) - 20px), calc(100% - 52px));
  width: 56px;
  height: 56px;
  border-radius: 50%;
  transform: translateX(-50%);
  background: linear-gradient(145deg, #f9fbff, #ccdfff);
  box-shadow:
    0 12px 26px rgba(0,0,0,.32),
    0 0 0 1px rgba(255,255,255,.42) inset;
  transition: bottom .36s cubic-bezier(.22, 1, .36, 1);
}

.nlc-slider-sun {
  position: absolute;
  right: 4px;
  color: rgba(210,222,244,.48);
  --mdc-icon-size: 28px;
}

.nlc-slider-sun-top {
  top: 6px;
}

.nlc-slider-sun-bottom {
  bottom: 38px;
}

.nlc-slider-horizontal {
  top: calc(170px * var(--nlc-y-scale));
  width: var(--nlc-slider-horizontal-width, 282px);
  height: 122px;
  transform-origin: top center;
}

.nlc-slider-horizontal .nlc-slider-shell {
  left: 0;
  top: 35px;
  width: 100%;
  height: 62px;
}

.nlc-slider-horizontal .nlc-slider-fill {
  left: 12px;
  right: auto;
  top: 10px;
  bottom: 10px;
  width: var(--nlc-brightness);
  max-width: calc(100% - 24px);
  height: auto;
  background: linear-gradient(90deg, var(--nlc-alt), color-mix(in srgb, var(--nlc-current) 88%, white 8%));
}

.nlc-slider-horizontal .nlc-slider-knob {
  left: clamp(28px, var(--nlc-brightness), calc(100% - 28px));
  top: 50%;
  bottom: auto;
  transform: translate(-50%, -50%);
  transition: left .36s cubic-bezier(.22, 1, .36, 1);
}

.nlc-slider-horizontal .nlc-slider-sun {
  right: auto;
}

.nlc-slider-horizontal .nlc-slider-sun-top {
  right: -2px;
  top: 0;
}

.nlc-slider-horizontal .nlc-slider-sun-bottom {
  left: -2px;
  bottom: 0;
}

.neo-light-card[data-style="circle-button"] .nlc-circle-button {
  display: grid;
}

.nlc-circle-button {
  left: 50%;
  top: calc(106px * var(--nlc-y-scale));
  width: 212px;
  height: 212px;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  place-items: center;
  border-radius: 50%;
  background:
    radial-gradient(circle, color-mix(in srgb, var(--nlc-current) 12%, transparent), transparent 62%),
    rgba(10,18,30,.42);
}

.nlc-circle-ring {
  position: absolute;
  inset: 30px;
  border-radius: 50%;
  border: 7px solid var(--nlc-current);
  opacity: .9;
  box-shadow:
    0 0 24px color-mix(in srgb, var(--nlc-current) 38%, transparent),
    inset 0 0 20px color-mix(in srgb, var(--nlc-current) 14%, transparent);
}

.nlc-circle-button ha-icon {
  color: var(--nlc-current);
  --mdc-icon-size: 56px;
}

.neo-light-card[data-active="off"] .nlc-circle-ring {
  border-color: rgba(96,111,138,.45);
  box-shadow: none;
}

.neo-light-card[data-style="icon-switch"] .nlc-icon-switch {
  display: grid;
}

.nlc-icon-switch {
  left: 50%;
  right: auto;
  top: calc(128px * var(--nlc-y-scale));
  width: 276px;
  height: 154px;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  grid-template-columns: 1fr 1fr;
  border-radius: 28px;
  overflow: hidden;
  background: rgba(21,31,49,.78);
  box-shadow: inset 0 1px 0 rgba(255,255,255,.07);
}

.nlc-icon-side {
  display: grid;
  place-items: center;
  align-content: center;
  gap: 10px;
  color: rgba(212,224,245,.54);
  font-size: 20px;
  font-weight: 800;
  letter-spacing: .03em;
  transition: background .28s ease, color .28s ease, transform .28s ease;
}

.nlc-icon-side ha-icon {
  --mdc-icon-size: 52px;
}

.neo-light-card[data-active="on"] .nlc-icon-side-on,
.neo-light-card[data-active="off"] .nlc-icon-side-off {
  color: #2c2410;
  background: linear-gradient(145deg, #fff1a6, var(--nlc-current));
  transform: scale(1.03);
  box-shadow: 0 18px 36px color-mix(in srgb, var(--nlc-current) 25%, transparent);
}

.neo-light-card[data-active="off"] .nlc-icon-side-off {
  color: rgba(230,238,252,.62);
  background: rgba(31,43,64,.74);
  box-shadow: inset 0 1px 0 rgba(255,255,255,.07);
}

.neo-light-card[data-style="rocker-switch"] .nlc-rocker {
  display: grid;
}

.nlc-rocker {
  left: 50%;
  top: calc(82px * var(--nlc-y-scale));
  width: 124px;
  height: 238px;
  box-sizing: border-box;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  grid-template-rows: 1fr 1fr;
  padding: 12px;
  gap: 10px;
  border-radius: 42px;
  background: rgba(3,8,16,.72);
  border: 1px solid rgba(170,190,225,.16);
  box-shadow:
    inset 0 1px 0 rgba(255,255,255,.08),
    0 20px 42px rgba(0,0,0,.32);
}

.nlc-rocker-half {
  display: grid;
  place-items: center;
  border-radius: 27px;
  color: rgba(232,240,255,.78);
  font-size: 38px;
  font-weight: 500;
  background: linear-gradient(180deg, rgba(255,255,255,.06), rgba(255,255,255,.02));
  box-shadow: inset 0 1px 0 rgba(255,255,255,.1);
}

.neo-light-card[data-active="on"] .nlc-rocker-top,
.neo-light-card[data-active="off"] .nlc-rocker-bottom {
  color: white;
  background: linear-gradient(145deg, color-mix(in srgb, var(--nlc-current) 76%, white 4%), color-mix(in srgb, var(--nlc-alt) 58%, #1d2556));
  box-shadow:
    0 0 22px color-mix(in srgb, var(--nlc-current) 30%, transparent),
    inset 0 1px 0 rgba(255,255,255,.24);
}

.neo-light-card[data-style="card-switch"] .nlc-card-switch {
  display: block;
}

.nlc-card-switch {
  left: 50%;
  top: calc(98px * var(--nlc-y-scale));
  width: 248px;
  height: 260px;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
}

.nlc-card-inner {
  height: 100%;
  display: grid;
  place-items: center;
  align-content: center;
  gap: 20px;
  border-radius: 28px;
  background: linear-gradient(160deg, rgba(255,255,255,.08), rgba(255,255,255,.025));
  border: 1px solid rgba(170,190,225,.12);
  box-shadow: inset 0 1px 0 rgba(255,255,255,.08);
}

.nlc-card-inner ha-icon {
  color: var(--nlc-current);
  --mdc-icon-size: 78px;
  filter: drop-shadow(0 0 22px color-mix(in srgb, var(--nlc-current) 48%, transparent));
}

.nlc-card-name {
  max-width: 190px;
  color: rgba(232,240,255,.74);
  font-size: 22px;
  font-weight: 700;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.nlc-card-pill {
  width: 190px;
  height: 52px;
  display: grid;
  place-items: center;
  border-radius: 999px;
  color: #211808;
  background: linear-gradient(180deg, #ffe978, var(--nlc-current));
  font-size: 21px;
  font-weight: 900;
  box-shadow: 0 18px 34px color-mix(in srgb, var(--nlc-current) 22%, transparent);
}

.neo-light-card[data-active="off"] .nlc-card-pill {
  color: rgba(232,240,255,.56);
  background: rgba(70,84,108,.42);
  box-shadow: none;
}

.neo-light-card[data-style="dot-switch"] .nlc-dot-stack {
  display: grid;
}

.nlc-dot-stack {
  left: 50%;
  top: calc(98px * var(--nlc-y-scale));
  width: 78px;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  justify-items: center;
  gap: 24px;
}

.nlc-dot-stack button {
  appearance: none;
  border: 0;
  padding: 0;
  cursor: pointer;
  width: 58px;
  height: 58px;
  border-radius: 50%;
  background: rgba(65,79,103,.46);
  box-shadow: inset 0 1px 0 rgba(255,255,255,.08);
}

.nlc-dot-stack button.is-active {
  background: linear-gradient(145deg, color-mix(in srgb, var(--nlc-current) 86%, white 8%), var(--nlc-alt));
  box-shadow:
    0 0 28px color-mix(in srgb, var(--nlc-current) 36%, transparent),
    inset 0 1px 0 rgba(255,255,255,.3);
}

.neo-light-card[data-active="off"] .nlc-dot-stack button.is-active {
  background: rgba(246,251,255,.82);
  box-shadow:
    0 0 22px rgba(246,251,255,.24),
    inset 0 1px 0 rgba(255,255,255,.2);
}

.neo-light-card[data-style="ring-dimmer"] .nlc-ring-dimmer {
  display: grid;
}

.nlc-ring-dimmer {
  left: 50%;
  top: calc(88px * var(--nlc-y-scale));
  width: 230px;
  height: 230px;
  transform: translateX(-50%) scale(var(--nlc-ui-scale));
  transform-origin: top center;
  place-items: center;
  touch-action: none;
}

.nlc-ring-outer {
  position: relative;
  width: 214px;
  height: 214px;
  border-radius: 50%;
  background:
    conic-gradient(from 0deg, var(--nlc-current) 0 var(--nlc-brightness), rgba(63,78,104,.45) var(--nlc-brightness) 100%);
  box-shadow:
