.neo-light-card[data-style="ring-dimmer"] .nlc-top-icon { top: calc(24px * var(--nlc-y-scale)); }
.neo-light-card[data-style="minimal-dot"] .nlc-top-icon { top: calc(32px * var(--nlc-y-scale)); }
