  gap: 6px;
  margin-bottom: 12px;
  color: rgba(247,251,255,.7);
  font-size: 13px;
  font-weight: 700;
}

.nlc-entity-field {
  position: relative;
}

.nlc-entity-menu {
  display: none;
  max-height: 190px;
  overflow-y: auto;
  gap: 4px;
  margin-top: 2px;
  padding: 6px;
  box-sizing: border-box;
  border-radius: 14px;
  border: 1px solid rgba(150,190,255,.18);
  background:
    radial-gradient(circle at 18% 0%, color-mix(in srgb, var(--nlc-current) 16%, transparent), transparent 42%),
    linear-gradient(145deg, rgba(16,25,42,.98), rgba(8,14,26,.98));
  box-shadow: none;
}

.nlc-entity-menu.open {
  display: grid;
}

.nlc-entity-option {
  width: 100%;
  min-height: 48px;
  display: grid;
  gap: 2px;
  padding: 8px 10px;
  border: 0;
  border-radius: 10px;
  box-sizing: border-box;
  color: #f7fbff;
  text-align: left;
  background: transparent;
  cursor: pointer;
}

.nlc-entity-option:hover,
.nlc-entity-option.active {
  background: color-mix(in srgb, var(--nlc-current) 18%, rgba(255,255,255,.06));
}

.nlc-entity-option strong {
  overflow: hidden;
  color: rgba(247,251,255,.92);
  font-size: 13px;
  font-weight: 850;
  line-height: 1.2;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.nlc-entity-option span {
  overflow: hidden;
  color: rgba(247,251,255,.48);
  font-size: 11px;
  font-weight: 650;
  line-height: 1.25;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.nlc-entity-empty {
  padding: 12px 10px;
  color: rgba(247,251,255,.48);
  font-size: 12px;
  font-weight: 700;
  text-align: center;
}

.nlc-config-panel input,
.nlc-config-panel select {
  height: 38px;
  border-radius: 12px;
  border: 1px solid rgba(255,255,255,.12);
  padding: 0 12px;
  box-sizing: border-box;
  color: white;
  background: rgba(255,255,255,.06);
  outline: none;
}

.nlc-config-panel input:focus,
.nlc-config-panel select:focus {
  border-color: var(--nlc-current);
}

.nlc-config-panel input[type="color"] {
  padding: 4px;
}

.nlc-check {
  grid-template-columns: 20px 1fr;
  align-items: center;
}

.nlc-check input {
  width: 18px;
  height: 18px;
  padding: 0;
}

.nlc-config-close {
  position: absolute;
  top: 16px;
  right: 16px;
  width: 34px;
  height: 34px;
  border: 0;
  border-radius: 50%;
  color: white;
  background: rgba(255,255,255,.08);
  font-size: 24px;
  line-height: 1;
  cursor: pointer;
}

.nlc-save {
  width: 100%;
  height: 42px;
  margin-top: 8px;
  border: 0;
  border-radius: 14px;
  color: #06101a;
  background: var(--nlc-current);
  font-weight: 900;
  cursor: pointer;
}

card.js:
let liveHass = hass;

const card = root.querySelector('[data-neo-light]');
const stage = root.querySelector('[data-nlc-stage]');
const toggleTarget = root.querySelector('[data-nlc-toggle]');
const iconEl = root.querySelector('[data-nlc-icon]');
const topIconEl = root.querySelector('[data-nlc-top-icon]');
const labelEl = root.querySelector('[data-nlc-label]');
const statusEl = root.querySelector('[data-nlc-status]');
const percentEl = root.querySelector('[data-nlc-percent]');
const cardNameEl = root.querySelector('[data-nlc-card-name]');
const configOpen = root.querySelector('[data-nlc-config-open]');
const configPanel = root.querySelector('[data-nlc-config]');
const configClose = root.querySelector('[data-nlc-config-close]');
const configSave = root.querySelector('[data-nlc-config-save]');
const entityInput = root.querySelector('[data-nlc-entity-input]');
const entityMenu = root.querySelector('[data-nlc-entity-menu]');
const tunePanel = root.querySelector('[data-nlc-tune-panel]');
const tuneTitleEl = root.querySelector('[data-nlc-tune-title]');
const tuneClose = root.querySelector('[data-nlc-tune-close]');
const brightnessInput = root.querySelector('[data-nlc-brightness]');
const brightnessValueEl = root.querySelector('[data-nlc-brightness-value]');
const kelvinInput = root.querySelector('[data-nlc-kelvin]');
const kelvinValueEl = root.querySelector('[data-nlc-kelvin-value]');
const hueInput = root.querySelector('[data-nlc-hue]');
const saturationInput = root.querySelector('[data-nlc-saturation]');
const colorPreviewEl = root.querySelector('[data-nlc-color-preview]');

const DESIGN_W = 360;
const DESIGN_H = 500;
const NEO_CONFIG_FIELD = 'neo_light_config';
const STYLE_OPTIONS = new Set([
  'toggle-switch',
  'slider-switch',
  'slider-switch-horizontal',
  'circle-button',
  'icon-switch',
  'rocker-switch',
  'card-switch',
  'dot-switch',
  'ring-dimmer',
  'minimal-dot'
]);
const PERSISTED_CONFIG_KEYS = [
  'entity',
  'icon',
  'label',
  'style',
  'showBrightness',
  'showIcon',
  'showStatus',
  'defaultBrightness',
  'colorOn',
  'colorAlt',
  'colorOff'
];

let resizeFrame = null;
let lastSignature = '';
let lastStateSignature = '';
let lastScaleSignature = '';
let lastSurfaceSignature = '';
let surfaceMutationObserver = null;
let wrapperStyleSyncing = false;
let wrapperStyleSyncTimer = null;
let destroyed = false;
let optimisticState = null;
let pulseTimer = null;
let activeDimmer = null;
let tuneCommitTimer = null;
let tuneInteractionUntil = 0;
let entityMenuItems = [];
let entityMenuIndex = -1;
let entityBlurTimer = null;
let configPortalParent = null;
let configPortalNext = null;
const CONFIG_PORTAL_STYLE_ID = 'neo-light-card-config-portal-style-v1';
let tunePortalParent = null;
let tunePortalNext = null;
const TUNE_PORTAL_STYLE_ID = 'neo-light-card-tune-portal-style-v1';

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function numberOrFallback(value, fallback) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function boolAttr(value) {
  return ['true', '1', 'yes', 'on'].includes(String(value || '').toLowerCase());
}

function escapeHtml(value) {
  return String(value === undefined || value === null ? '' : value).replace(/[&<>"']/g, (char) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;'
  }[char]));
}

function cloneJson(value, fallback) {
  try {
    return JSON.parse(JSON.stringify(value));
  } catch {
    return fallback;
  }
}

function getCardWrapper() {
  return host && host.closest ? host.closest('.card-wrapper') : null;
}

function getConfigStorageKey() {
  const wrap = getCardWrapper();
  const cardId =
    (wrap && wrap.dataset && wrap.dataset.layoutCardId) ||
    (host && host.dataset && host.dataset.layoutCardId) ||
    (host && host.id) ||
    'default-card';

  let dashboardId = 'dashboard';
  try {
    dashboardId = String(
      (ddc && ddc.storageKey) ||
      (ddc && ddc.storage_key) ||
      (ddc && ddc.settings && ddc.settings.get && ddc.settings.get('storage_key')) ||
      (location && location.pathname) ||
      'dashboard'
    );
  } catch {}

  return 'neo-light-card-config:v1:' + dashboardId + ':' + cardId;
}

function isTransparentCssValue(value) {
  const v = String(value || '').trim().toLowerCase();
  if (!v) return false;
  if (v === 'transparent') return true;
  if (/rgba?\([^)]*,\s*0(?:\.0+)?\s*\)$/.test(v)) return true;
  if (/rgb\([^)]*\/\s*0(?:\.0+)?%?\s*\)$/.test(v)) return true;
  return false;
}

function readCssVariable(name) {
  const nodes = [card, stage, host, getCardWrapper()].filter(Boolean);
  for (const node of nodes) {
    try {
      const value = getComputedStyle(node).getPropertyValue(name).trim();
      if (value) return value;
    } catch {}
  }
  return '';
}

function parseStyleObject(value) {
  if (!value || typeof value !== 'string') return null;
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' ? parsed : null;
  } catch {
    return null;
  }
}

function firstSurfaceValue() {
  for (let i = 0; i < arguments.length; i += 1) {
    const value = String(arguments[i] || '').trim();
    if (value && !isTransparentCssValue(value)) return value;
  }
  return '';
}

function firstDeclaredSurfaceValue() {
  for (let i = 0; i < arguments.length; i += 1) {
    const value = String(arguments[i] || '').trim();
    if (value) return value;
  }

  return '';
}

function wrapperCardStyle() {
  const wrap = getCardWrapper();
  if (!wrap || !wrap.dataset) return null;
  return (
    parseStyleObject(wrap.dataset.cardStyle) ||
    parseStyleObject(wrap.dataset.card_style) ||
    parseStyleObject(wrap.dataset.style)
  );
}

function readDesignSurface() {
  const wrap = getCardWrapper();
  const style = wrapperCardStyle();
  const computed = wrap ? getComputedStyle(wrap) : null;

  const explicitSurface = firstDeclaredSurfaceValue(
    style && style.background,
    style && style.backgroundColor,
    style && style.background_color,
    style && style.cardBackground,
    style && style.card_background,
    style && style.card_background_color,
    style && style.containerBackground,
    style && style.container_background,
    style && style.container_background_color
  );

  if (explicitSurface) return explicitSurface;

  return firstSurfaceValue(
    readCssVariable('--ddc-card-inner-bg'),
    readCssVariable('--ddc-card-local-bg'),
    readCssVariable('--ddc-card-bg'),
    computed && computed.backgroundImage !== 'none' ? computed.backgroundImage : '',
    computed && computed.backgroundColor
  );
}

function isNoneCssValue(value) {
  const clean = String(value || '').trim().toLowerCase();
  return !clean || clean === 'none' || clean === '0' || clean === '0px';
}

function readDesignShadow() {
  const local = readCssVariable('--ddc-card-local-shadow');
  if (local) return local;
  const dashboard = readCssVariable('--ddc-card-shadow');
  if (dashboard) return dashboard;
  return 'none';
}

function splitShadowList(value) {
  const shadows = [];
  let current = '';
  let depth = 0;

  String(value || '').split('').forEach((char) => {
    if (char === '(') depth += 1;
    if (char === ')') depth = Math.max(0, depth - 1);

    if (char === ',' && depth === 0) {
      if (current.trim()) shadows.push(current.trim());
      current = '';
      return;
    }

    current += char;
  });

  if (current.trim()) shadows.push(current.trim());
  return shadows;
}

function isLengthToken(value) {
  return /^-?(?:\d+|\d*\.\d+)(?:px)?$/.test(String(value || '').trim());
}

function toPxNumber(value) {
  const num = Number(String(value || '').replace('px', ''));
  return Number.isFinite(num) ? num : 0;
}

function tightenShadowPart(value, shrink) {
  const parts = String(value || '').trim().split(/\s+/);
  const indexes = [];

  parts.forEach((part, index) => {
    if (isLengthToken(part)) indexes.push(index);
  });

  if (indexes.length >= 4) {
    const spreadIndex = indexes[3];
    parts[spreadIndex] = (toPxNumber(parts[spreadIndex]) - shrink) + 'px';
    return parts.join(' ');
  }

  if (indexes.length === 3) {
    parts.splice(indexes[2] + 1, 0, '-' + shrink + 'px');
    return parts.join(' ');
  }

  return value;
}

function tightenShadowValue(value, shrink) {
  if (isNoneCssValue(value)) return 'none';
  return splitShadowList(value)
    .map((shadow) => tightenShadowPart(shadow, shrink))
    .join(', ');
}

function setStylePropertyIfChanged(node, name, value) {
  if (!node || !node.style) return;
  if (node.style.getPropertyValue(name) !== value) node.style.setProperty(name, value);
}

function setStyleFieldIfChanged(node, name, value) {
  if (!node || !node.style) return;
  if (node.style[name] !== value) node.style[name] = value;
}

function removeStylePropertyIfPresent(node, name) {
  if (!node || !node.style) return;
  if (node.style.getPropertyValue(name)) node.style.removeProperty(name);
}

function releaseWrapperStyleSyncFlag() {
  if (wrapperStyleSyncTimer) clearTimeout(wrapperStyleSyncTimer);
  wrapperStyleSyncTimer = setTimeout(() => {
    wrapperStyleSyncTimer = null;
    wrapperStyleSyncing = false;
  }, 0);
}

function keepWrapperTransparent() {
  const wrap = getCardWrapper();
  const nodes = [wrap, host].filter(Boolean);
  if (!nodes.length) return;

  wrapperStyleSyncing = true;

  try {
    nodes.forEach((node) => {
      try {
        setStylePropertyIfChanged(node, '--ddc-card-local-bg', 'transparent');
        setStylePropertyIfChanged(node, '--ddc-card-inner-bg', 'transparent');
        setStylePropertyIfChanged(node, '--ha-card-background', 'transparent');
        setStylePropertyIfChanged(node, '--card-background-color', 'transparent');
        setStyleFieldIfChanged(node, 'background', 'transparent');
        setStyleFieldIfChanged(node, 'boxShadow', 'none');
        setStyleFieldIfChanged(node, 'overflow', 'visible');

        if (node === wrap) {
          const editing = node.classList && (node.classList.contains('editing') || node.classList.contains('dragging'));

          if (!editing) {
            setStyleFieldIfChanged(node, 'border', '0 solid transparent');
            setStyleFieldIfChanged(node, 'outline', 'none');
          } else {
            removeStylePropertyIfPresent(node, 'border');
            removeStylePropertyIfPresent(node, 'outline');
          }
        }
      } catch {}
    });
  } finally {
    releaseWrapperStyleSyncFlag();
  }
}

function syncDesignSurface() {
  if (!card || destroyed) return;

  const surface = readDesignSurface();
  const transparent = !surface || isTransparentCssValue(surface);
  const signature = transparent ? 'transparent' : surface;

  if (signature !== lastSurfaceSignature) {
    lastSurfaceSignature = signature;
    if (transparent) {
      card.dataset.surface = 'transparent';
      card.style.removeProperty('--nlc-design-surface');
    } else {
      delete card.dataset.surface;
      card.style.setProperty('--nlc-design-surface', surface);
    }
  }

  keepWrapperTransparent();
}

function readSourceCardConfig() {
  const wrap = getCardWrapper();

  try {
    const parsed = JSON.parse((wrap && wrap.dataset && wrap.dataset.cfg) || 'null');
    if (parsed && typeof parsed === 'object') return parsed;
  } catch {}

  if (host && host.__ddcSourceConfig && typeof host.__ddcSourceConfig === 'object') {
    return cloneJson(host.__ddcSourceConfig, host.__ddcSourceConfig);
  }

  if (host && host._config && typeof host._config === 'object') {
    return cloneJson(host._config, host._config);
  }

  if (config && typeof config === 'object') {
    return cloneJson(config, config);
  }

  return { type: 'custom:ddc-html-card' };
}

function normalizeSwitchStyle(value) {
  const next = String(value || '').trim().toLowerCase();
  return STYLE_OPTIONS.has(next) ? next : 'toggle-switch';
}

function normalizeConfigValues(values) {
  if (!values || typeof values !== 'object') return null;
  const out = {};

  PERSISTED_CONFIG_KEYS.forEach((key) => {
    if (values[key] === undefined || values[key] === null) return;
    out[key] = String(values[key]);
  });

  if (out.style) out.style = normalizeSwitchStyle(out.style);
  return Object.keys(out).length ? out : null;
}

function applyConfigObject(values) {
  const normalized = normalizeConfigValues(values);
  if (!normalized) return;

  PERSISTED_CONFIG_KEYS.forEach((key) => {
    if (normalized[key] === undefined || normalized[key] === null) return;
    card.dataset[key] = normalized[key];
  });
}

function readLocalConfig() {
  try {
    const raw = localStorage.getItem(getConfigStorageKey());
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return normalizeConfigValues(parsed && parsed.values && typeof parsed.values === 'object' ? parsed.values : parsed);
  } catch {
    return null;
  }
}

function readDurableConfig() {
  const direct = normalizeConfigValues(config && config[NEO_CONFIG_FIELD]);
  if (direct) return direct;

  const source = readSourceCardConfig();
  return normalizeConfigValues(source && source[NEO_CONFIG_FIELD]);
}

function readPersistedConfig() {
  return readDurableConfig() || readLocalConfig();
}

function applyPersistedConfig() {
  applyConfigObject(readPersistedConfig());
}

function collectCurrentConfig() {
  return {
    entity: getEntityId(),
    icon: getIcon(),
    label: getLabel(),
    style: getSwitchStyle(),
    showBrightness: getShowBrightness() ? 'true' : 'false',
    showIcon: getShowIcon() ? 'true' : 'false',
    showStatus: getShowStatus() ? 'true' : 'false',
    defaultBrightness: String(getDefaultBrightness()),
    colorOn: card.dataset.colorOn || '#ffd95a',
    colorAlt: card.dataset.colorAlt || '#4aa7ff',
    colorOff: card.dataset.colorOff || '#6f7f96'
  };
}

function updateHtmlSourceWithConfig(html, values) {
  if (typeof html !== 'string' || !html.trim()) return html;

  try {
    const template = document.createElement('template');
    template.innerHTML = html;
    const sourceCard = template.content.querySelector('[data-neo-light]');
    if (!sourceCard) return html;

    PERSISTED_CONFIG_KEYS.forEach((key) => {
      if (values[key] === undefined || values[key] === null) return;
      sourceCard.dataset[key] = String(values[key]);
    });

    return template.innerHTML.trim();
  } catch {
    return html;
  }
}

function writeConfigToDdcSource(values) {
  const normalized = normalizeConfigValues(values);
  if (!normalized) return null;

  const wrap = getCardWrapper();
  const source = readSourceCardConfig();
  const next = {
    ...source,
    type: source && source.type ? source.type : 'custom:ddc-html-card',
    [NEO_CONFIG_FIELD]: normalized
  };

  next.html = updateHtmlSourceWithConfig(next.html, normalized);

  try { config[NEO_CONFIG_FIELD] = normalized; } catch {}
  try { host.__ddcSourceConfig = cloneJson(next, next); } catch {}
  try {
    if (host && host._config && typeof host._config === 'object') {
      host._config = { ...host._config, [NEO_CONFIG_FIELD]: normalized, html: next.html };
    }
  } catch {}
  try {
    if (wrap && wrap.dataset) wrap.dataset.cfg = JSON.stringify(next);
  } catch {}

  try {
    const cardId = wrap && wrap.dataset && wrap.dataset.layoutCardId;
    const owner = ddc && ddc.card;
    if (owner && cardId && typeof owner._updateCardConfigAcrossResponsiveLayouts_ === 'function') {
      owner._updateCardConfigAcrossResponsiveLayouts_(cardId, next);
    }
  } catch {}

  return next;
}

function requestDeferredLayoutSave(reason) {
  const saveReason = reason || 'neo-light-config';
  let queued = false;

  try {
    const owner = ddc && ddc.card;
    if (owner && typeof owner._queueSave === 'function') {
      owner._queueSave(saveReason);
      queued = true;
    }
  } catch {}

  try {
    const owner = ddc && ddc.card;
    if (!queued && owner && typeof owner._markDirty === 'function') {
      owner._markDirty(saveReason);
      queued = true;
    }
  } catch {}

  return queued;
}

async function saveCurrentLayout() {
  let saved = false;

  try {
    const owner = ddc && ddc.card;
    try { owner && owner._persistCurrentResponsiveProfileToMemory_ && owner._persistCurrentResponsiveProfileToMemory_({ syncMembership: true }); } catch {}
    try { owner && owner._syncLiveCardConfigsIntoResponsiveLayouts_ && owner._syncLiveCardConfigsIntoResponsiveLayouts_(); } catch {}

    if (ddc && typeof ddc.saveLayout === 'function') {
      await ddc.saveLayout(true);
      saved = true;
    } else if (owner && typeof owner._saveLayout === 'function') {
      await owner._saveLayout(true);
      saved = true;
    }
  } catch {}

  if (!saved) {
    saved = requestDeferredLayoutSave('neo-light-config');
  }

  return saved;
}

async function persistCurrentConfig() {
  const values = collectCurrentConfig();

  try {
    localStorage.setItem(getConfigStorageKey(), JSON.stringify({
      version: 1,
      updatedAt: new Date().toISOString(),
      values
    }));
  } catch {}

  const savedConfig = writeConfigToDdcSource(values);
  if (!savedConfig) return false;

  return saveCurrentLayout();
}

function getEntityId() {
  return card.dataset.entity || card.getAttribute('entity') || 'light.living_room';
}

function getEntityFriendlyName(entityId) {
  const stateObj = liveHass && liveHass.states ? liveHass.states[entityId] : null;
  return (stateObj && stateObj.attributes && stateObj.attributes.friendly_name) || entityId;
}

function getEntitySuggestions(query) {
  const states = liveHass && liveHass.states ? liveHass.states : {};
  const search = String(query || '').trim().toLowerCase();
  const domains = new Set(['light', 'switch']);

  return Object.keys(states)
    .filter((entityId) => {
      const domain = String(entityId).split('.')[0];
      if (!domains.has(domain)) return false;
      if (!search) return true;

      const friendly = getEntityFriendlyName(entityId).toLowerCase();
      return entityId.toLowerCase().includes(search) || friendly.includes(search);
    })
    .sort((a, b) => {
      const da = a.split('.')[0] === 'light' ? 0 : 1;
      const db = b.split('.')[0] === 'light' ? 0 : 1;
      if (da !== db) return da - db;
      return getEntityFriendlyName(a).localeCompare(getEntityFriendlyName(b), undefined, { sensitivity: 'base' });
    })
    .slice(0, 40)
    .map((entityId) => ({
      entityId,
      name: getEntityFriendlyName(entityId)
    }));
}

function renderEntityMenu(searchValue) {
  if (!entityInput || !entityMenu) return;

  entityMenuItems = getEntitySuggestions(searchValue === undefined ? entityInput.value : searchValue);
  entityMenuIndex = clamp(entityMenuIndex, -1, entityMenuItems.length - 1);

  if (!entityMenuItems.length) {
    entityMenu.innerHTML = '<div class="nlc-entity-empty">No matching lights or switches</div>';
    entityMenu.classList.add('open');
    return;
  }

  entityMenu.innerHTML = entityMenuItems.map((item, index) => (
    '<button type="button" class="nlc-entity-option' + (index === entityMenuIndex ? ' active' : '') + '" data-entity-id="' + escapeHtml(item.entityId) + '">' +
      '<strong>' + escapeHtml(item.name) + '</strong>' +
      '<span>' + escapeHtml(item.entityId) + '</span>' +
    '</button>'
  )).join('');
  entityMenu.classList.add('open');
}

function closeEntityMenu() {
  if (!entityMenu) return;
  entityMenu.classList.remove('open');
  entityMenuIndex = -1;
}

function chooseEntity(entityId) {
  if (!entityInput || !entityId) return;
  entityInput.value = entityId;
  closeEntityMenu();
}

function getIcon() {
  return card.dataset.icon || card.getAttribute('icon') || 'mdi:lightbulb-outline';
}

function getLabel() {
  return card.dataset.label || card.getAttribute('label') || 'Light';
}

function getSwitchStyle() {
  return normalizeSwitchStyle(card.dataset.style || card.getAttribute('style-mode') || 'toggle-switch');
}

function getShowBrightness() {
  return boolAttr(card.dataset.showBrightness || card.getAttribute('show-brightness'));
}

function getShowIcon() {
  const value = card.dataset.showIcon ?? card.getAttribute('show-icon');
  return value === undefined || value === null || value === '' ? true : boolAttr(value);
}

function getShowStatus() {
  const value = card.dataset.showStatus ?? card.getAttribute('show-status');
  return value === undefined || value === null || value === '' ? true : boolAttr(value);
}

function getDefaultBrightness() {
  return clamp(Math.round(numberOrFallback(card.dataset.defaultBrightness || card.getAttribute('default-brightness'), 75)), 1, 100);
}

function getDomain() {
  return String(getEntityId()).split('.')[0] || 'light';
}

function canDim() {
  return getDomain() === 'light';
}

function getStateObj() {
  return liveHass && liveHass.states ? liveHass.states[getEntityId()] : null;
}

function getSupportedColorModes() {
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const modes = Array.isArray(attrs.supported_color_modes) ? attrs.supported_color_modes.map((mode) => String(mode).toLowerCase()) : [];
  return modes;
}

function hasBrightnessSupport() {
  if (getDomain() !== 'light') return false;
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const modes = getSupportedColorModes();
  if (attrs.brightness !== undefined && attrs.brightness !== null) return true;
  return modes.some((mode) => ['brightness', 'color_temp', 'hs', 'xy', 'rgb', 'rgbw', 'rgbww', 'white'].includes(mode));
}

function styleHasInlineBrightness(style) {
  return ['slider-switch', 'slider-switch-horizontal', 'ring-dimmer', 'dot-switch'].includes(normalizeSwitchStyle(style));
}

function hasTemperatureSupport() {
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const modes = getSupportedColorModes();
  return modes.includes('color_temp') || attrs.min_color_temp_kelvin || attrs.max_color_temp_kelvin || attrs.min_mireds || attrs.max_mireds;
}

function hasColorSupport() {
  const modes = getSupportedColorModes();
  return modes.some((mode) => ['hs', 'xy', 'rgb', 'rgbw', 'rgbww'].includes(mode));
}

function getKelvinRange() {
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const min = numberOrFallback(attrs.min_color_temp_kelvin, 2000);
  const max = numberOrFallback(attrs.max_color_temp_kelvin, 6500);
  return { min: Math.round(Math.min(min, max)), max: Math.round(Math.max(min, max)) };
}

function currentKelvin() {
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const range = getKelvinRange();
  return clamp(Math.round(numberOrFallback(attrs.color_temp_kelvin, Math.round((range.min + range.max) / 2))), range.min, range.max);
}

function currentHsColor() {
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const hs = Array.isArray(attrs.hs_color) ? attrs.hs_color : [45, 80];
  return {
    hue: clamp(Math.round(numberOrFallback(hs[0], 45)), 0, 360),
    saturation: clamp(Math.round(numberOrFallback(hs[1], 80)), 0, 100)
  };
}

function kelvinToCssColor(kelvin) {
  const t = clamp((numberOrFallback(kelvin, 3500) - 2000) / 4500, 0, 1);
  const r = Math.round(255 + (247 - 255) * t);
  const g = Math.round(172 + (251 - 172) * t);
  const b = Math.round(72 + (255 - 72) * t);
  return 'rgb(' + r + ', ' + g + ', ' + b + ')';
}

function liveColorValue() {
  const attrs = (getStateObj() && getStateObj().attributes) || {};
  const mode = String(attrs.color_mode || '').toLowerCase();
  if (hasColorSupport() && mode !== 'color_temp') {
    const hs = currentHsColor();
    return 'hsl(' + hs.hue + ', ' + hs.saturation + '%, 56%)';
  }
  if (hasTemperatureSupport()) return kelvinToCssColor(currentKelvin());
  if (hasColorSupport()) {
    const hs = currentHsColor();
    return 'hsl(' + hs.hue + ', ' + hs.saturation + '%, 56%)';
  }
  return '';
}

function applyTuneCssVars(hue, saturation, liveColor) {
  const sat = String(clamp(Math.round(numberOrFallback(saturation, 80)), 0, 100)) + '%';
  const h = String(clamp(Math.round(numberOrFallback(hue, 45)), 0, 360));
  [card, tunePanel, colorPreviewEl, saturationInput].filter(Boolean).forEach((node) => {
    try {
      node.style.setProperty('--nlc-hue', h);
      node.style.setProperty('--nlc-saturation', sat);
    } catch {}
  });
  if (liveColor) card.style.setProperty('--nlc-live-color', liveColor);
}

function markTuneInteraction() {
  tuneInteractionUntil = Date.now() + 1800;
}

function isTuneInputActive() {
  if (Date.now() < tuneInteractionUntil) return true;
  const active = (root && root.activeElement) || document.activeElement;
  return !!(tunePanel && tunePanel.classList.contains('open') && active && tunePanel.contains(active) && active.matches && active.matches('input[type="range"]'));
}

function normalizedHsForService(hue, saturation) {
  const h = clamp(Math.round(numberOrFallback(hue, 0)), 0, 360);
  const s = h >= 360 ? 0 : clamp(Math.round(numberOrFallback(saturation, 0)), 0, 100);
  return [h >= 360 ? 0 : h, s];
}

function hsToRgb(hue, saturation) {
  const hs = normalizedHsForService(hue, saturation);
  const h = hs[0] / 60;
  const s = hs[1] / 100;
  const v = 1;
  const c = v * s;
  const x = c * (1 - Math.abs((h % 2) - 1));
  const m = v - c;
  let r = 0, g = 0, b = 0;
  if (h >= 0 && h < 1) [r, g, b] = [c, x, 0];
  else if (h < 2) [r, g, b] = [x, c, 0];
  else if (h < 3) [r, g, b] = [0, c, x];
  else if (h < 4) [r, g, b] = [0, x, c];
  else if (h < 5) [r, g, b] = [x, 0, c];
  else [r, g, b] = [c, 0, x];
  return [
    Math.round((r + m) * 255),
    Math.round((g + m) * 255),
    Math.round((b + m) * 255)
  ];
}

function getLightData() {
  const stateObj = getStateObj();
  const now = Date.now();

  if (optimisticState && optimisticState.until > now) {
    return {
      on: optimisticState.on,
      percent: optimisticState.percent,
      state: optimisticState.on ? 'on' : 'off',
      unavailable: false
    };
  }

  optimisticState = null;
  const rawState = String((stateObj && stateObj.state) || 'unavailable').toLowerCase();
  const unavailable = !stateObj || ['unavailable', 'unknown', 'none'].includes(rawState);
  const on = rawState === 'on';
  const rawBrightness = Number(stateObj && stateObj.attributes && stateObj.attributes.brightness);
  const percent = on
    ? clamp(Math.round(Number.isFinite(rawBrightness) ? (rawBrightness / 255) * 100 : getDefaultBrightness()), 1, 100)
    : 0;

  return {
    on,
    percent,
    state: unavailable ? 'unavailable' : rawState,
    unavailable
  };
}

function applyPulse() {
  if (pulseTimer) clearTimeout(pulseTimer);
  card.dataset.stateChange = 'pulse';
  pulseTimer = setTimeout(() => {
    pulseTimer = null;
    if (!destroyed) delete card.dataset.stateChange;
  }, 700);
}

function setOptimistic(on, percent) {
  optimisticState = {
    on: Boolean(on),
    percent: clamp(Math.round(percent), 0, 100),
    until: Date.now() + 1400
  };
  applyPulse();
  lastSignature = '';
  render(true);
}

async function callLightTune(data) {
  if (!liveHass || !liveHass.callService || getDomain() !== 'light') return;
  const payload = Object.assign({ entity_id: getEntityId() }, data || {});
  await liveHass.callService('light', 'turn_on', payload);
}

function syncTuneControls(force = false) {
  if (!tunePanel) return;
  if (!force && isTuneInputActive()) return;

  const range = getKelvinRange();
  const kelvin = currentKelvin();
  const hs = currentHsColor();
  const lightData = getLightData();

  if (brightnessInput) brightnessInput.value = String(lightData.percent || 0);
  if (brightnessValueEl) brightnessValueEl.textContent = String(lightData.percent || 0) + '%';

  if (kelvinInput) {
    kelvinInput.min = String(range.min);
    kelvinInput.max = String(range.max);
    kelvinInput.value = String(kelvin);
  }
  if (kelvinValueEl) kelvinValueEl.textContent = kelvin + ' K';
  if (hueInput) hueInput.value = String(hs.hue);
  if (saturationInput) saturationInput.value = String(hs.saturation);
  applyTuneCssVars(hs.hue, hs.saturation, liveColorValue());
}

function openTunePanel(mode) {
  if (!tunePanel) return;
  tunePanel.dataset.mode = mode;
  if (tuneTitleEl) tuneTitleEl.textContent = mode === 'brightness' ? 'Brightness' : (mode === 'temperature' ? 'Warmth' : 'Color');
  mountTunePortal();
  syncTuneControls(true);
  tunePanel.classList.add('open');
}

function closeTunePanel() {
  if (!tunePanel) return;
  tunePanel.classList.remove('open');
  unmountTunePortal();
}

function updateBrightnessPreview() {
  if (!brightnessInput) return;
  markTuneInteraction();
  const value = clamp(Math.round(numberOrFallback(brightnessInput.value, 0)), 0, 100);
  if (brightnessValueEl) brightnessValueEl.textContent = value + '%';
  card.style.setProperty('--nlc-brightness', value + '%');
  card.style.setProperty('--nlc-ring-angle', (value * 3.6) + 'deg');
}

async function commitBrightness() {
  if (!brightnessInput) return;
  markTuneInteraction();
  const value = clamp(Math.round(numberOrFallback(brightnessInput.value, 0)), 0, 100);
  setBrightness(value);
}

function updateKelvinPreview() {
  if (!kelvinInput) return;
  markTuneInteraction();
  const value = clamp(Math.round(numberOrFallback(kelvinInput.value, currentKelvin())), getKelvinRange().min, getKelvinRange().max);
  if (kelvinValueEl) kelvinValueEl.textContent = value + ' K';
  card.style.setProperty('--nlc-live-color', kelvinToCssColor(value));
}

async function commitKelvin() {
  if (!kelvinInput) return;
  markTuneInteraction();
  const value = clamp(Math.round(numberOrFallback(kelvinInput.value, currentKelvin())), getKelvinRange().min, getKelvinRange().max);
  setOptimistic(true, getLightData().percent || getDefaultBrightness());
  card.style.setProperty('--nlc-live-color', kelvinToCssColor(value));
  try {
    await callLightTune({ color_temp_kelvin: value });
  } catch {
    try { await callLightTune({ kelvin: value }); } catch {}
  }
}

function updateColorPreview() {
  markTuneInteraction();
  const hue = clamp(Math.round(numberOrFallback(hueInput && hueInput.value, 45)), 0, 360);
  const saturation = clamp(Math.round(numberOrFallback(saturationInput && saturationInput.value, 80)), 0, 100);
  const hs = normalizedHsForService(hue, saturation);
  const live = hs[1] <= 0 ? '#f7fbff' : 'hsl(' + hs[0] + ', ' + hs[1] + '%, 56%)';
  applyTuneCssVars(hue, hs[1], live);
}

async function commitColor() {
  markTuneInteraction();
  const hue = clamp(Math.round(numberOrFallback(hueInput && hueInput.value, 45)), 0, 360);
  const saturation = clamp(Math.round(numberOrFallback(saturationInput && saturationInput.value, 80)), 0, 100);
  const hs = normalizedHsForService(hue, saturation);
  const live = hs[1] <= 0 ? '#f7fbff' : 'hsl(' + hs[0] + ', ' + hs[1] + '%, 56%)';
  setOptimistic(true, getLightData().percent || getDefaultBrightness());
  applyTuneCssVars(hue, hs[1], live);
  try {
    await callLightTune({ hs_color: hs });
  } catch {
    try { await callLightTune({ rgb_color: hsToRgb(hue, saturation) }); } catch {}
  }
}

async function callEntityService(on, percent) {
  if (!liveHass || !liveHass.callService) return;

  const entityId = getEntityId();
  const domain = getDomain() === 'switch' ? 'switch' : 'light';
  const service = on ? 'turn_on' : 'turn_off';
  const data = { entity_id: entityId };

  if (domain === 'light' && on && Number.isFinite(percent)) {
    data.brightness_pct = clamp(Math.round(percent), 1, 100);
  }

  await liveHass.callService(domain, service, data);
}

async function setLightState(nextOn, percent) {
  const safePercent = nextOn ? clamp(Math.round(percent || getDefaultBrightness()), 1, 100) : 0;
  setOptimistic(nextOn, safePercent);

  try {
    await callEntityService(nextOn, safePercent);
  } catch {
    optimisticState = null;
    lastSignature = '';
    render(true);
  }
}

function toggleLight() {
  const data = getLightData();
  return setLightState(!data.on, data.on ? 0 : (data.percent || getDefaultBrightness()));
}

function setBrightness(percent) {
  const safePercent = clamp(Math.round(numberOrFallback(percent, 0)), 0, 100);
  if (!canDim()) return setLightState(safePercent > 0, safePercent > 0 ? 100 : 0);
  return setLightState(safePercent > 0, safePercent);
}

function getViewportElement() {
  return (root && root.parentElement) ||
    (host && host.shadowRoot && host.shadowRoot.querySelector && host.shadowRoot.querySelector('.runtime')) ||
    host ||
    (card && card.parentElement) ||
    card;
}

function getViewportSize() {
  const viewport = getViewportElement();
  const width =
    (viewport && viewport.clientWidth) ||
    (root && root.clientWidth) ||
    (card && card.parentElement && card.parentElement.clientWidth) ||
    DESIGN_W;
  const height =
    (viewport && viewport.clientHeight) ||
    (root && root.clientHeight) ||
    (card && card.parentElement && card.parentElement.clientHeight) ||
    DESIGN_H;

  return {
    width: Math.max(50, width),
    height: Math.max(50, height)
  };
}

function updateScale() {
  if (!card || !stage || destroyed) return;

  const size = getViewportSize();
  const scaleX = size.width / DESIGN_W;
  const scaleY = size.height / DESIGN_H;
  const uiScale = clamp(Math.min(scaleX, scaleY), 0.45, 3);
  const stretchX = scaleX / uiScale;
  const stretchY = scaleY / uiScale;
  const horizontalSliderWidth = Math.round(282 * stretchX);
  const verticalSliderHeight = Math.round(272 * stretchY);
  const verticalSliderShellHeight = Math.round(238 * stretchY);
  const radius = Math.max(12, Math.round(42 * uiScale));
  const signature = [
    Math.round(size.width),
    Math.round(size.height),
    scaleX.toFixed(5),
    scaleY.toFixed(5),
    uiScale.toFixed(5),
    stretchX.toFixed(5),
    stretchY.toFixed(5)
  ].join('|');

  if (signature === lastScaleSignature) return;
  lastScaleSignature = signature;

  card.style.width = '100%';
  card.style.height = size.height + 'px';
  card.style.minHeight = '0';
  card.style.overflow = 'visible';
  card.style.setProperty('--nlc-x-scale', scaleX);
  card.style.setProperty('--nlc-y-scale', scaleY);
  card.style.setProperty('--nlc-ui-scale', uiScale);
  card.style.setProperty('--nlc-radius', radius + 'px');
  card.style.setProperty('--nlc-slider-horizontal-width', horizontalSliderWidth + 'px');
  card.style.setProperty('--nlc-slider-vertical-height', verticalSliderHeight + 'px');
  card.style.setProperty('--nlc-slider-vertical-shell-height', verticalSliderShellHeight + 'px');
  card.style.removeProperty('--nlc-shadow-pad');

  stage.style.width = size.width + 'px';
  stage.style.height = size.height + 'px';
  stage.style.left = '0';
  stage.style.top = '0';
  stage.style.transform = 'none';
  stage.style.boxShadow = 'none';
  stage.style.borderRadius = radius + 'px';
}

function scheduleScale() {
  if (destroyed) return;
  if (resizeFrame) cancelAnimationFrame(resizeFrame);
  resizeFrame = requestAnimationFrame(() => {
    resizeFrame = null;
    updateScale();
  });
}

const resizeObserver = new ResizeObserver(() => {
  syncDesignSurface();
  scheduleScale();
});

Array.from(new Set([getViewportElement(), root, card].filter(Boolean))).forEach((el) => {
  try { resizeObserver.observe(el); } catch {}
});

try {
  const wrap = getCardWrapper();
  if (wrap && typeof MutationObserver !== 'undefined') {
    surfaceMutationObserver = new MutationObserver(() => {
      if (destroyed || wrapperStyleSyncing) return;
      syncDesignSurface();
    });
    surfaceMutationObserver.observe(wrap, {
      attributes: true,
      attributeFilter: ['style', 'data-card-style', 'data-card_style', 'class']
    });
  }
} catch {}

