function mountConfigPortal() {
  if (!configPanel) return;

  updatePortalColor(configPanel);

  try {
    ensureConfigPortalStyle();
    if (!document || !document.body || configPanel.parentNode === document.body) return;
    configPortalParent = configPanel.parentNode;
    configPortalNext = configPanel.nextSibling;
    document.body.appendChild(configPanel);
  } catch {}
}

function unmountConfigPortal() {
  try {
    if (!configPanel || !document || configPanel.parentNode !== document.body) return;
    if (configPortalParent && configPortalParent.isConnected) {
      if (configPortalNext && configPortalNext.parentNode === configPortalParent) {
