    style.textContent = ".nlc-tune-backdrop {\n  position: fixed;\n  inset: 0;\n  z-index: 2147482999;\n  width: 100vw;\n  height: 100vh;\n  display: none;\n  place-items: center;\n  padding: clamp(18px, 4vw, 44px);\n  box-sizing: border-box;\n  background: rgba(2, 5, 11, .70);\n  backdrop-filter: blur(16px) saturate(.82);\n  pointer-events: none;\n  overflow-y: auto;\n  font-family: var(--paper-font-body1_-_font-family, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif);\n}\n\n.nlc-tune-backdrop.open {\n  display: grid;\n  pointer-events: auto;\n}\n\n.nlc-tune-panel {\n  position: relative;\n  width: min(340px, calc(100vw - 36px));\n  max-width: 100%;\n  max-height: calc(100vh - 48px);\n  overflow-y: auto;\n  padding: 24px;\n  box-sizing: border-box;\n  border-radius: 26px;\n  border: 1px solid rgba(255,255,255,.13);\n  color: #f7fbff;\n  background:\n    radial-gradient(circle at 24% 0%, color-mix(in srgb, var(--nlc-current, #ffd95a) 14%, transparent), transparent 38%),\n    linear-gradient(145deg, #0b1220, #111b2f);\n  box-shadow: 0 28px 90px rgba(0,0,0,.54);\n}\n\n.nlc-tune-panel h3 {\n  margin: 0 0 18px;\n  font-size: 22px;\n  font-weight: 900;\n}\n\n.nlc-tune-section {\n  display: none;\n  gap: 14px;\n}\n\n.nlc-tune-backdrop[data-mode=\"brightness\"] [data-nlc-brightness-section],\n.nlc-tune-backdrop[data-mode=\"temperature\"] [data-nlc-temperature-section],\n.nlc-tune-backdrop[data-mode=\"color\"] [data-nlc-color-section] {\n  display: grid;\n}\n\n.nlc-tune-section label {\n  display: grid;\n  gap: 8px;\n  color: rgba(247,251,255,.72);\n  font-size: 13px;\n  font-weight: 800;\n}\n\n.nlc-tune-section input[type=\"range\"] {\n  appearance: none;\n  width: 100%;\n  height: 16px;\n  border-radius: 999px;\n  border: 1px solid rgba(255,255,255,.12);\n  outline: none;\n  box-shadow:\n    inset 0 1px 0 rgba(255,255,255,.12),\n    inset 0 -1px 0 rgba(0,0,0,.28);\n  cursor: pointer;\n}\n\n.nlc-tune-section input[type=\"range\"]::-webkit-slider-thumb {\n  appearance: none;\n  width: 24px;\n  height: 24px;\n  border-radius: 50%;\n  border: 2px solid rgba(8,13,24,.74);\n  background: #f7fbff;\n  box-shadow:\n    0 5px 14px rgba(0,0,0,.38),\n    0 0 0 1px rgba(255,255,255,.36);\n}\n\n.nlc-tune-section input[type=\"range\"]::-moz-range-thumb {\n  width: 22px;\n  height: 22px;\n  border-radius: 50%;\n  border: 2px solid rgba(8,13,24,.74);\n  background: #f7fbff;\n  box-shadow:\n    0 5px 14px rgba(0,0,0,.38),\n    0 0 0 1px rgba(255,255,255,.36);\n}\n\n.nlc-tune-backdrop [data-nlc-brightness] {\n  background: linear-gradient(90deg, rgba(85,99,126,.64), color-mix(in srgb, var(--nlc-current, #ffd95a) 94%, white 10%));\n}\n\n.nlc-tune-backdrop [data-nlc-kelvin] {\n  background: linear-gradient(90deg, #ff8f3d 0%, #ffd47b 32%, #fff4cc 52%, #d7ebff 76%, #94bdff 100%);\n}\n\n.nlc-tune-backdrop [data-nlc-hue] {\n  background: linear-gradient(90deg, hsl(0, 92%, 56%), hsl(45, 96%, 58%), hsl(95, 82%, 50%), hsl(170, 82%, 48%), hsl(220, 86%, 60%), hsl(285, 86%, 60%), hsl(330, 88%, 62%), #f7fbff);\n}\n\n.nlc-tune-backdrop [data-nlc-saturation] {\n  background: linear-gradient(90deg, #f7fbff, hsl(var(--nlc-hue, 45), 100%, 56%));\n}\n\n.nlc-tune-value {\n  color: rgba(247,251,255,.62);\n  font-size: 13px;\n  font-weight: 700;\n}\n\n.nlc-color-preview {\n  width: 100%;\n  height: 46px;\n  border-radius: 14px;\n  border: 1px solid rgba(255,255,255,.12);\n  background:\n    radial-gradient(circle at calc(var(--nlc-saturation, 80%) * 1%) 50%, rgba(255,255,255,.36), transparent 10%),\n    hsl(var(--nlc-hue, 45), var(--nlc-saturation, 80%), 55%);\n  box-shadow:\n    inset 0 1px 0 rgba(255,255,255,.18),\n    0 0 22px hsl(var(--nlc-hue, 45), var(--nlc-saturation, 80%), 42%, .24);\n}\n\n.nlc-tune-close {\n  position: absolute;\n  top: 14px;\n  right: 14px;\n  width: 34px;\n  height: 34px;\n  border: 0;\n  border-radius: 50%;\n  color: white;\n  background: rgba(255,255,255,.08);\n  font-size: 24px;\n  line-height: 1;\n  cursor: pointer;\n}";
    document.head.appendChild(style);
  } catch {}
}

function mountTunePortal() {
  if (!tunePanel) return;

  updatePortalColor(tunePanel);

  try {
    ensureTunePortalStyle();
    if (!document || !document.body || tunePanel.parentNode === document.body) return;
    tunePortalParent = tunePanel.parentNode;
    tunePortalNext = tunePanel.nextSibling;
    document.body.appendChild(tunePanel);
  } catch {}
}

function unmountTunePortal() {
  try {
    if (!tunePanel || !document || tunePanel.parentNode !== document.body) return;
    if (tunePortalParent && tunePortalParent.isConnected) {
      if (tunePortalNext && tunePortalNext.parentNode === tunePortalParent) {
        tunePortalParent.insertBefore(tunePanel, tunePortalNext);
      } else {
        tunePortalParent.appendChild(tunePanel);
      }
    } else {
      tunePanel.remove();
    }
  } catch {}

  tunePortalParent = null;
  tunePortalNext = null;
}

function setConfigInput(name, value) {
  const input = queryConfigControl('[data-cfg="' + name + '"]');
  if (!input) return;

  if (input.type === 'checkbox') {
    input.checked = Boolean(value);
  } else {
    input.value = value === undefined || value === null ? '' : value;
  }
}

function getConfigInput(name) {
  const input = queryConfigControl('[data-cfg="' + name + '"]');
  if (!input) return '';

  if (input.type === 'checkbox') return input.checked;
  return input.value;
}

function openConfig() {
  setConfigInput('entity', getEntityId());
  setConfigInput('icon', getIcon());
  setConfigInput('label', getLabel());
  setConfigInput('style', getSwitchStyle());
  setConfigInput('showBrightness', getShowBrightness());
  setConfigInput('showIcon', getShowIcon());
  setConfigInput('showStatus', getShowStatus());
  setConfigInput('defaultBrightness', getDefaultBrightness());
  setConfigInput('colorOn', card.dataset.colorOn || '#ffd95a');
  setConfigInput('colorAlt', card.dataset.colorAlt || '#4aa7ff');
  setConfigInput('colorOff', card.dataset.colorOff || '#6f7f96');

  closeEntityMenu();
  mountConfigPortal();
  configPanel.classList.add('open');
}

function closeConfig() {
  closeEntityMenu();
  configPanel.classList.remove('open');
  unmountConfigPortal();
}

async function saveConfig() {
  applyConfigObject({
    entity: getConfigInput('entity'),
    icon: getConfigInput('icon'),
    label: getConfigInput('label'),
    style: getConfigInput('style'),
    showBrightness: getConfigInput('showBrightness') ? 'true' : 'false',
    showIcon: getConfigInput('showIcon') ? 'true' : 'false',
    showStatus: getConfigInput('showStatus') ? 'true' : 'false',
    defaultBrightness: getConfigInput('defaultBrightness'),
    colorOn: getConfigInput('colorOn'),
    colorAlt: getConfigInput('colorAlt'),
    colorOff: getConfigInput('colorOff')
  });

  const persistPromise = persistCurrentConfig();
  optimisticState = null;
  lastSignature = '';
  lastStateSignature = '';
  lastScaleSignature = '';

  render(true);
  closeConfig();

  try { await persistPromise; } catch {}
}

function percentFromDimmerEvent(ev, el, mode) {
  const rect = el.getBoundingClientRect();

  if (mode === 'vertical') {
    const y = clamp(ev.clientY - rect.top, 0, rect.height);
    return clamp(Math.round((1 - y / rect.height) * 100), 1, 100);
  }

  if (mode === 'horizontal') {
    const x = clamp(ev.clientX - rect.left, 0, rect.width);
    return clamp(Math.round((x / rect.width) * 100), 1, 100);
  }

  const cx = rect.left + rect.width / 2;
  const cy = rect.top + rect.height / 2;
  const dx = ev.clientX - cx;
  const dy = ev.clientY - cy;
  const deg = (Math.atan2(dy, dx) * 180 / Math.PI + 450) % 360;
  return clamp(Math.round((deg / 360) * 100), 0, 100);
}

function previewDimmer(ev) {
  if (!activeDimmer) return;
  const percent = percentFromDimmerEvent(ev, activeDimmer.el, activeDimmer.mode);
  setOptimistic(true, percent);
}

function commitDimmer(ev) {
  if (!activeDimmer) return;
  const percent = percentFromDimmerEvent(ev, activeDimmer.el, activeDimmer.mode);
  const target = activeDimmer.el;
  activeDimmer = null;
  try { target.releasePointerCapture(ev.pointerId); } catch {}
  setBrightness(percent);
}

function onDimmerPointerDown(ev) {
  const target = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-dimmer]') : null;
  if (!target) return;
  ev.preventDefault();
  ev.stopPropagation();

  activeDimmer = {
    el: target,
    mode: target.dataset.nlcDimmer || 'vertical'
  };

  try { target.setPointerCapture(ev.pointerId); } catch {}
  previewDimmer(ev);
}

function onDimmerPointerMove(ev) {
  if (!activeDimmer) return;
  ev.preventDefault();
  ev.stopPropagation();
  previewDimmer(ev);
}

function onDimmerPointerUp(ev) {
  if (!activeDimmer) return;
  ev.preventDefault();
  ev.stopPropagation();
  commitDimmer(ev);
}

function onToggleClick(ev) {
  const tuneTarget = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-tune-panel], .nlc-tune-panel, [data-nlc-tune-open]') : null;
  if (tuneTarget) return;
  const dotTarget = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-dot-level]') : null;
  const commandTarget = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-command]') : null;
  const dimmerTarget = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-dimmer]') : null;
  if (dimmerTarget) return;

  if (dotTarget) {
    ev.preventDefault();
    ev.stopPropagation();
    const level = clamp(Math.round(numberOrFallback(dotTarget.dataset.nlcDotLevel, 0)), 0, 100);
    return setBrightness(level);
  }

  if (commandTarget) {
    ev.preventDefault();
    ev.stopPropagation();
    const command = commandTarget.dataset.nlcCommand;
    if (command === 'on') return setLightState(true, getLightData().percent || getDefaultBrightness());
    if (command === 'off') return setLightState(false, 0);
  }

  ev.preventDefault();
  ev.stopPropagation();
  toggleLight();
}

function onToggleKey(ev) {
  if (ev.key !== 'Enter' && ev.key !== ' ') return;
  ev.preventDefault();
  toggleLight();
}

const onConfigOpen = (ev) => {
  ev.stopPropagation();
  openConfig();
};

const onConfigClose = (ev) => {
  ev.stopPropagation();
  closeConfig();
};

const onConfigSave = (ev) => {
  ev.stopPropagation();
  saveConfig();
};

const onConfigBackdrop = (ev) => {
  if (ev.target === configPanel) closeConfig();
};

const onEntityInput = () => {
  entityMenuIndex = -1;
  renderEntityMenu();
};

const onEntityFocus = () => {
  if (entityBlurTimer) clearTimeout(entityBlurTimer);
  entityMenuIndex = -1;
  renderEntityMenu('');
};

const onEntityBlur = () => {
  entityBlurTimer = setTimeout(() => {
    entityBlurTimer = null;
    closeEntityMenu();
  }, 120);
};

const onEntityKeydown = (ev) => {
  if (!entityInput || !entityMenu) return;

  if (ev.key === 'ArrowDown') {
    ev.preventDefault();
    if (!entityMenu.classList.contains('open')) renderEntityMenu();
    entityMenuIndex = entityMenuItems.length ? (entityMenuIndex + 1) % entityMenuItems.length : -1;
    renderEntityMenu();
    return;
  }

  if (ev.key === 'ArrowUp') {
    ev.preventDefault();
    if (!entityMenu.classList.contains('open')) renderEntityMenu();
    entityMenuIndex = entityMenuItems.length ? (entityMenuIndex <= 0 ? entityMenuItems.length - 1 : entityMenuIndex - 1) : -1;
    renderEntityMenu();
    return;
  }

  if (ev.key === 'Enter' && entityMenu.classList.contains('open') && entityMenuIndex >= 0 && entityMenuItems[entityMenuIndex]) {
    ev.preventDefault();
    chooseEntity(entityMenuItems[entityMenuIndex].entityId);
    return;
  }

  if (ev.key === 'Escape') {
    ev.preventDefault();
    closeEntityMenu();
  }
};

const onEntityMenuPointerDown = (ev) => {
  const option = ev.target && ev.target.closest ? ev.target.closest('[data-entity-id]') : null;
  if (!option) return;
  ev.preventDefault();
  ev.stopPropagation();
  chooseEntity(option.dataset.entityId);
};

const onTuneOpen = (ev) => {
  const btn = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-tune-open]') : null;
  if (!btn) return;
  ev.preventDefault();
  ev.stopPropagation();
  if (ev.stopImmediatePropagation) ev.stopImmediatePropagation();
  openTunePanel(btn.dataset.nlcTuneOpen || 'temperature');
};

const onTuneClose = (ev) => {
  ev.preventDefault();
  ev.stopPropagation();
  closeTunePanel();
};

const onTuneBackdrop = (ev) => {
  ev.stopPropagation();
  if (ev.target === tunePanel) closeTunePanel();
};

const onTunePointerStop = (ev) => {
  ev.stopPropagation();
};

function scheduleTuneCommit(fn) {
  if (tuneCommitTimer) clearTimeout(tuneCommitTimer);
  tuneCommitTimer = setTimeout(() => {
    tuneCommitTimer = null;
    try { fn(); } catch {}
  }, 180);
}

const onBrightnessInput = () => {
  updateBrightnessPreview();
  scheduleTuneCommit(commitBrightness);
};
const onBrightnessChange = () => commitBrightness();

const onKelvinInput = () => {
  updateKelvinPreview();
  scheduleTuneCommit(commitKelvin);
};
const onKelvinChange = () => commitKelvin();
const onColorInput = () => {
  updateColorPreview();
  scheduleTuneCommit(commitColor);
};
const onColorChange = () => commitColor();

toggleTarget.addEventListener('click', onTuneOpen);
toggleTarget.addEventListener('click', onToggleClick);
toggleTarget.addEventListener('keydown', onToggleKey);
toggleTarget.addEventListener('pointerdown', onDimmerPointerDown);
toggleTarget.addEventListener('pointermove', onDimmerPointerMove);
toggleTarget.addEventListener('pointerup', onDimmerPointerUp);
toggleTarget.addEventListener('pointercancel', onDimmerPointerUp);
configOpen.addEventListener('click', onConfigOpen);
configClose.addEventListener('click', onConfigClose);
configSave.addEventListener('click', onConfigSave);
configPanel.addEventListener('click', onConfigBackdrop);
if (entityInput) {
  entityInput.addEventListener('input', onEntityInput);
  entityInput.addEventListener('focus', onEntityFocus);
  entityInput.addEventListener('blur', onEntityBlur);
  entityInput.addEventListener('keydown', onEntityKeydown);
}
if (entityMenu) entityMenu.addEventListener('pointerdown', onEntityMenuPointerDown);
if (tuneClose) tuneClose.addEventListener('click', onTuneClose);
if (tunePanel) {
  tunePanel.addEventListener('click', onTuneBackdrop);
  tunePanel.addEventListener('pointerdown', onTunePointerStop);
  tunePanel.addEventListener('pointermove', onTunePointerStop);
  tunePanel.addEventListener('pointerup', onTunePointerStop);
}
if (brightnessInput) {
  brightnessInput.addEventListener('input', onBrightnessInput);
  brightnessInput.addEventListener('change', onBrightnessChange);
}
if (kelvinInput) {
  kelvinInput.addEventListener('input', onKelvinInput);
  kelvinInput.addEventListener('change', onKelvinChange);
}
if (hueInput) {
  hueInput.addEventListener('input', onColorInput);
  hueInput.addEventListener('change', onColorChange);
}
if (saturationInput) {
  saturationInput.addEventListener('input', onColorInput);
  saturationInput.addEventListener('change', onColorChange);
}

function makeHassStateSignature() {
  const entityId = getEntityId();
  const stateObj = liveHass && liveHass.states ? liveHass.states[entityId] : null;
  return [
    entityId,
    stateObj && stateObj.state || '',
    stateObj && stateObj.last_changed || '',
    stateObj && stateObj.last_updated || '',
    stateObj && stateObj.attributes && stateObj.attributes.brightness || '',
    stateObj && stateObj.attributes && stateObj.attributes.color_mode || '',
    stateObj && stateObj.attributes && stateObj.attributes.color_temp_kelvin || '',
    stateObj && stateObj.attributes && stateObj.attributes.hs_color || '',
    stateObj && stateObj.attributes && stateObj.attributes.supported_color_modes || ''
  ].join('|');
}

function render(force) {
  if (destroyed) return;

  syncDesignSurface();

  const data = getLightData();
  const style = getSwitchStyle();
  const entityId = getEntityId();
  const icon = getIcon();
  const label = getLabel();
  const showBrightness = getShowBrightness();
  const showIcon = getShowIcon();
  const showStatus = getShowStatus();
  const hasBrightness = hasBrightnessSupport();
  const hasTemperature = hasTemperatureSupport();
  const hasColor = hasColorSupport();
  const showBrightnessTool = hasBrightness && !styleHasInlineBrightness(style);
  const hs = currentHsColor();
  const kelvin = currentKelvin();
  const liveColor = liveColorValue();
  const colorOn = card.dataset.colorOn || '#ffd95a';
  const colorAlt = card.dataset.colorAlt || '#4aa7ff';
  const colorOff = card.dataset.colorOff || '#6f7f96';

  const signature = [
    entityId,
    icon,
    label,
    style,
    data.state,
    data.on,
    data.percent,
    data.unavailable,
    showBrightness,
    showIcon,
    showStatus,
    hasBrightness,
    hasTemperature,
    hasColor,
    showBrightnessTool,
    hs.hue,
    hs.saturation,
    kelvin,
    liveColor,
    colorOn,
    colorAlt,
    colorOff,
    lastSurfaceSignature
  ].join('|');

  if (!force && signature === lastSignature) {
    updateScale();
    return;
  }

  lastSignature = signature;

  card.dataset.style = style;
  card.dataset.active = data.on ? 'on' : 'off';
  card.dataset.unavailable = data.unavailable ? 'true' : 'false';
  card.dataset.showBrightness = showBrightness ? 'true' : 'false';
  card.dataset.showIcon = showIcon ? 'true' : 'false';
  card.dataset.showStatus = showStatus ? 'true' : 'false';
  card.dataset.hasBrightness = hasBrightness ? 'true' : 'false';
  card.dataset.hasTemperature = hasTemperature ? 'true' : 'false';
  card.dataset.hasColor = hasColor ? 'true' : 'false';
  card.dataset.showBrightnessTool = showBrightnessTool ? 'true' : 'false';
  card.dataset.hasLightTools = hasTemperature || hasColor ? 'true' : 'false';
  card.style.setProperty('--nlc-on', colorOn);
  card.style.setProperty('--nlc-alt', colorAlt);
  card.style.setProperty('--nlc-off', colorOff);
  card.style.setProperty('--nlc-brightness', data.percent + '%');
  card.style.setProperty('--nlc-ring-angle', (data.percent * 3.6) + 'deg');
  applyTuneCssVars(hs.hue, hs.saturation, liveColor);

  toggleTarget.setAttribute('aria-label', (data.on ? 'Turn off ' : 'Turn on ') + label);
  toggleTarget.setAttribute('aria-pressed', data.on ? 'true' : 'false');
  iconEl.setAttribute('icon', icon);
  if (topIconEl) topIconEl.setAttribute('icon', icon);
  labelEl.textContent = label;
  cardNameEl.textContent = label;
  statusEl.textContent = data.unavailable ? 'Unavailable' : (data.on ? 'ON' : 'OFF');
  percentEl.textContent = data.percent + '%';

  const cardPill = root.querySelector('.nlc-card-pill');
  if (cardPill) cardPill.textContent = data.on ? 'ON' : 'OFF';

  root.querySelectorAll('[data-nlc-dot-level]').forEach((button) => {
    const level = Number(button.dataset.nlcDotLevel);
    const active =
      (!data.on && level === 0) ||
      (data.on && data.percent >= 75 && level === 100) ||
      (data.on && data.percent > 0 && data.percent < 75 && level === 50);
    button.classList.toggle('is-active', active);
  });

  syncTuneControls(false);

  updateScale();
}

applyPersistedConfig();
syncDesignSurface();
render(true);
updateScale();

return {
  update(ctx) {
    liveHass = (ctx && ctx.hass) || (host && host.hass) || liveHass;
    const stateSignature = makeHassStateSignature();
    if (stateSignature === lastStateSignature) {
      updateScale();
      return;
    }
    lastStateSignature = stateSignature;
    render(false);
  },
  destroy() {
    destroyed = true;
    try { resizeObserver.disconnect(); } catch {}
    try { surfaceMutationObserver && surfaceMutationObserver.disconnect && surfaceMutationObserver.disconnect(); } catch {}
    if (wrapperStyleSyncTimer) clearTimeout(wrapperStyleSyncTimer);
    wrapperStyleSyncTimer = null;
    wrapperStyleSyncing = false;
    if (resizeFrame) cancelAnimationFrame(resizeFrame);
    try { configPanel && configPanel.classList && configPanel.classList.remove('open'); } catch {}
    try { tunePanel && tunePanel.classList && tunePanel.classList.remove('open'); } catch {}
    unmountConfigPortal();
    unmountTunePortal();
    if (pulseTimer) clearTimeout(pulseTimer);
    if (tuneCommitTimer) clearTimeout(tuneCommitTimer);
    toggleTarget.removeEventListener('click', onToggleClick);
    toggleTarget.removeEventListener('keydown', onToggleKey);
    toggleTarget.removeEventListener('pointerdown', onDimmerPointerDown);
    toggleTarget.removeEventListener('pointermove', onDimmerPointerMove);
    toggleTarget.removeEventListener('pointerup', onDimmerPointerUp);
    toggleTarget.removeEventListener('pointercancel', onDimmerPointerUp);
    configOpen.removeEventListener('click', onConfigOpen);
    configClose.removeEventListener('click', onConfigClose);
    configSave.removeEventListener('click', onConfigSave);
    configPanel.removeEventListener('click', onConfigBackdrop);
    if (entityBlurTimer) clearTimeout(entityBlurTimer);
    if (entityInput) {
      entityInput.removeEventListener('input', onEntityInput);
      entityInput.removeEventListener('focus', onEntityFocus);
      entityInput.removeEventListener('blur', onEntityBlur);
      entityInput.removeEventListener('keydown', onEntityKeydown);
    }
    if (entityMenu) entityMenu.removeEventListener('pointerdown', onEntityMenuPointerDown);
    toggleTarget.removeEventListener('click', onTuneOpen);
    if (tuneClose) tuneClose.removeEventListener('click', onTuneClose);
    if (tunePanel) {
      tunePanel.removeEventListener('click', onTuneBackdrop);
      tunePanel.removeEventListener('pointerdown', onTunePointerStop);
      tunePanel.removeEventListener('pointermove', onTunePointerStop);
      tunePanel.removeEventListener('pointerup', onTunePointerStop);
    }
    if (brightnessInput) {
      brightnessInput.removeEventListener('input', onBrightnessInput);
      brightnessInput.removeEventListener('change', onBrightnessChange);
    }
    if (kelvinInput) {
      kelvinInput.removeEventListener('input', onKelvinInput);
      kelvinInput.removeEventListener('change', onKelvinChange);
    }
    if (hueInput) {
      hueInput.removeEventListener('input', onColorInput);
      hueInput.removeEventListener('change', onColorChange);
    }
    if (saturationInput) {
      saturationInput.removeEventListener('input', onColorInput);
      saturationInput.removeEventListener('change', onColorChange);
    }
  }
};

card.css:
:host {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 0;
}

ha-card,
.shell,
.runtime,
.runtime-content {
  width: 100% !important;
  height: 100% !important;
  min-height: 0 !important;
  box-sizing: border-box !important;
  background: transparent !important;
  box-shadow: none !important;
}

.shell {
  padding: 0 !important;
  gap: 0 !important;
  overflow: visible !important;
}

.runtime,
.runtime-content {
  overflow: visible !important;
}

.neo-light-card {
  --nlc-on: #ffd95a;
  --nlc-alt: #4aa7ff;
  --nlc-off: #6f7f96;
  --nlc-current: var(--nlc-off);
  --nlc-brightness: 0%;
  --nlc-default-surface: linear-gradient(145deg, #0a0f1c, #121a2b 58%, #070b13);
